INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1061, 185658, 13, 544, '一个城', '很旧的北京城，很远的秋天，很多美丽的地名，喜欢上面曾经风流的痕迹，如同藏在中古的传说。经过一个叫牡丹园的地方，可惜这里并没有锦缎一样的花朵。还有玉渊潭，好象那里不止是烟水潋滟，那么，夕照街又何曾有残阳如血？还有厢红旗，蓝旗营，正白旗，蓝靛厂里可煮过成匹的蓝花布？八大胡同里是否花钿委地无人收拾？颐和园里彩绘的抄手游廊，厂甸庙会民间的花红柳绿，还有长长树影的柳荫街，小小温润的后海，王府公候们的奢华宅第，如今百姓的寻常巷陌，王谢堂前的燕子来了又去，去了又来。撒落在这个城市里的脚印，有一天能否一一捡回来？
<br>
<br>这个城市的美丽总是看不够说不完，人道一日看尽长安花，我说无人知晓锦城花开第几重。陈丹燕说过只有异乡人才能最准地切入一个城市的美艳之处，很对很对。那个澳大利亚女子本世纪初拍的老北京黑白图片展，看到时怔住了。那才是我梦中的北京，还叫北平的年代，林海音笔下的城南旧事，厚厚白雪掩映着的完好城墙，悠悠走着的骆驼队，在城根儿晒太阳的穿棉袍的汉子，吹着玻璃弹着棉花旧书店里修着经卷的工匠，张自忠路上颓唐的西式建筑，琉璃厂青玉一般的街道，冬天萧瑟的枝桠，划过的天空破碎如宋瓷上的冰纹，是旧得这样美丽的一个城，不管不问不止不休的破碎华美，声声慢的节拍，随时可以夹进《老照片》里。后来胡同与城墙越拆越少，自己说过这个城市总在迫不及待的逃离它的过去。我的北京只有中华世纪坛前那条长长的水道，刻着失落的年表，一步步从夏商周走到二OOO，好象自己真穿越了五千年尘封的历史。多么喜爱博物馆里乏人问津的河姆陶罐与清朝斗彩，还有北展的俄式建筑，尖顶上一颗红星寥落地在黑夜闪亮，残存着社会主义初期的浪漫。北土城的蓟门烟树与灼灼桃花，银锭桥边的桨声�G乃与灯影摇红。故宫门上馒头大的门钉，斑驳的红色宫墙，秋天坐在长椅上眯着眼睛晒太阳。街上慢慢游走的无轨电车，缓缓刹车的声音象一声叹息。地安门上陈升犹自唱着《北京一夜》，人民大会堂里帕尔曼的小提琴一拉一顿，琴声如夜幕沉沉袭来，他颌首顽童一样的笑。西山黛色的峰峦，天边微微烧着的晚霞。还剩下什么，北城的繁华，南城的凋败，东城的奢靡，西城的富贵，是谁苍老的声音说着一层秋雨一层凉呢。
<br>
<br>在北京呆了几年的人，对这个城市会有深深的认同。问问街上口音不一的各色人等，往往都说自己的老家并不在这里。那么要在这里住过三百年的人，才是最地道的北京人了吧。南城有个袁崇焕祠，当年袁崇焕冤死菜市口，一个佘姓卫兵冒死把他的遗体偷出来埋葬，并叮嘱后人要祖祖代代给大帅守灵。后来清朝为了安抚人心厚葬袁崇焕，佘家后人就名正言顺的当起了守墓人，这一守三百多年过去了，现在还有一个佘家老太太还在干这件事。袁崇焕与佘姓卫兵都是东莞人，他们永远再回不去自己的故乡。特别着迷于这个传奇，北京城里有多少这样的故事？
<br> 
<br>中秋晚上在昆玉河边走，月亮恁好，河里有游船迤逦而过，情侣在河堤上点着蜡烛吃月饼，有人在草坪上架起天文望远镜，我惊喜地看到了月亮上的伤痕。夜深了，人声笑语渐行渐远，一如回过头再也看不见的锦绣阑珊。哪家小餐馆的水煮鱼最好吃，哪里的烤肉最地道，哪家音像店的DVD又多又便宜，哪个小菜市场的花摊卖的大束玫瑰花，哪处护城河边哪哪都是紫色小野菊和酸浆草，都是微微搓着手的疼爱与欢喜。如果一生中有十年的光阴已付托给一个人一个城。如果整整的一生会付托给一个人一个城。
<br>
<br>有人说，淡如水的相逢，浩大的曾经。有人说，要用一种歌咏的方式，写这个城市。', '很旧的北京城，很远的秋天，很多美丽的地名，喜欢上面曾经风流的痕迹，如同藏在中古的传说。经过一个叫牡丹园的地方，可惜这里并没有锦缎一样的花朵。还有玉渊潭，好象那里不止是烟水潋滟，那么，夕照街又何曾有残阳如血？还有厢红旗，蓝旗营，正白旗，蓝靛厂里可煮过成匹的蓝花布？八大胡同里是否花钿委地无人收拾？颐和园里彩绘的抄手游廊，厂甸庙会民间的花红柳绿，还有长长树影的柳荫街，小小温润的后海，王府公候们的奢华宅第，如今百姓的寻常巷陌，王谢堂前的燕子来了又去，去了又来。撒落在这个城市里的脚印，有一天能否一一捡回来？

